using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer()
    .WithHttpTransport(options =>
    {
        // Stateless mode is recommended when the server doesn't need
        // server-to-client requests like sampling or elicitation.
        options.Stateless = true;
    })
    .WithToolsFromAssembly()
    .WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();

app.Run();

// ── Tools ──────────────────────────────────────────────────────────

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo(string message) => $"Echo: {message}";
}

[McpServerToolType]
public static class WeatherTool
{
    [McpServerTool(Name = "get_weather"), Description("Gets the current weather for a given city.")]
    public static string GetWeather(string city) =>
        JsonSerializer.Serialize(new { city, tempC = 22, condition = "Sunny" });
}

// ── Resources ──────────────────────────────────────────────────────

[McpServerResourceType]
public class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json")]
    [Description("Returns the current application configuration.")]
    public static string GetAppSettings() =>
        JsonSerializer.Serialize(new
        {
            theme = "dark",
            language = "en",
            maxRetries = 3,
            featureFlags = new { darkMode = true, betaFeatures = false }
        });
}

[McpServerResourceType]
public class DocumentResources
{
    [McpServerResource(
        UriTemplate = "docs://articles/{id}",
        Name = "Article")]
    [Description("Returns an article by its ID.")]
    public static TextResourceContents GetArticle(string id)
    {
        // In a real app this would query a database or file system.
        var articles = new Dictionary<string, string>
        {
            ["1"] = "# Getting Started\n\nWelcome to the MCP server.",
            ["2"] = "# Advanced Usage\n\nLearn about resource templates."
        };

        if (!articles.TryGetValue(id, out var text))
            throw new McpException($"Article not found: {id}");

        return new TextResourceContents
        {
            Uri = $"docs://articles/{id}",
            MimeType = "text/markdown",
            Text = text
        };
    }
}

